{
var mode = GetChoice(parameters, "selectionMode", "index");
var index = Math.Clamp(GetInt(parameters, "index", 0), 0, 3);
var threshold = GetFloat(parameters, "threshold", 0.5f);
var seed = GetInt(parameters, "seed", context.Seed);

var size = context.TileSize;

// Determine selection
var selected = 0;

switch (mode)
{
    case "threshold":
    {
        // Use control value from input 0
        var controlVal = threshold;
        if (inputs.Length > 0 && inputs[0] != null)
        {
            var (r, _, _, _) = inputs[0]!.GetPixel(0, 0);
            controlVal = r;
        }
        selected = controlVal > threshold ? 1 : 0;
        break;
    }
    case "noise":
    {
        // Random selection based on seed
        var hash = HashToUnit(seed, context.Seed * 7, 12345);
        selected = (int)(hash * 4f) % 4;
        break;
    }
    default: // index
        selected = Math.Clamp(index, 0, 3);
        break;
}

// Select input (offset by 1 since input 0 is control)
var inputIdx = selected + 1;
var input = inputIdx < inputs.Length && inputs[inputIdx] != null
    ? inputs[inputIdx]!
    : new PixelBuffer(size, size);

// If no specific input connected, fall back to first available image input
if (input == null || (inputIdx < inputs.Length && inputs[inputIdx] == null))
{
    for (var i = 1; i < inputs.Length; i++)
    {
        if (inputs[i] != null)
        {
            input = inputs[i]!;
            break;
        }
    }
}

return input.Clone();
}
